buggyStarterCode.python:
class Solution:
    def solve(self, css_string):
        styles = css_string.split('style=')
        total_height = 0
        for i in range(1, len(styles)):
            style = styles[i].split('height:')[1].split('px')[0]
            total_height += int(style)
        return 'height: ' + str(total_height) + 'px'

